// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import {IERC165} from "./IERC165.sol";
import {IReceiver} from "./IReceiver.sol";
import {Ownable} from "@openzeppelin/contracts/access/Ownable.sol";

/// @title ReceiverTemplate - Abstract receiver with optional permission controls
/// @notice Provides flexible, updatable security checks for receiving workflow reports
/// @dev The forwarder address is required at construction time for security.
///      Additional permission fields can be configured using setter functions.
abstract contract ReceiverTemplate is IReceiver, Ownable {
  // Required permission field at deployment, configurable after
  address private s_forwarderAddress; // If set, only this address can call onReport

  // Optional permission fields (all default to zero = disabled)
  address private s_expectedAuthor; // If set, only reports from this workflow owner are accepted
  bytes10 private s_expectedWorkflowName; // Only validated when s_expectedAuthor is also set
  bytes32 private s_expectedWorkflowId; // If set, only reports from this specific workflow ID are accepted

  // Hex character lookup table for bytes-to-hex conversion
  bytes private constant HEX_CHARS = "0123456789abcdef";

  // Custom errors
  error InvalidForwarderAddress();
  error InvalidSender(address sender, address expected);
  error InvalidAuthor(address received, address expected);
  error InvalidWorkflowName(bytes10 received, bytes10 expected);
  error InvalidWorkflowId(bytes32 received, bytes32 expected);
  error WorkflowNameRequiresAuthorValidation();

  // Events
  event ForwarderAddressUpdated(address indexed previousForwarder, address indexed newForwarder);
  event ExpectedAuthorUpdated(address indexed previousAuthor, address indexed newAuthor);
  event ExpectedWorkflowNameUpdated(bytes10 indexed previousName, bytes10 indexed newName);
  event ExpectedWorkflowIdUpdated(bytes32 indexed previousId, bytes32 indexed newId);
  event SecurityWarning(string message);

  /// @notice Constructor sets msg.sender as the owner and configures the forwarder address
  /// @param _forwarderAddress The address of the Chainlink Forwarder contract (cannot be address(0))
  /// @dev The forwarder address is required for security - it ensures only verified reports are processed
  constructor(
    address _forwarderAddress
  ) Ownable(msg.sender) {
    if (_forwarderAddress == address(0)) {
      revert InvalidForwarderAddress();
    }
    s_forwarderAddress = _forwarderAddress;
    emit ForwarderAddressUpdated(address(0), _forwarderAddress);
  }

  /// @notice Returns the configured forwarder address
  /// @return The forwarder address (address(0) if disabled)
  function getForwarderAddress() external view returns (address) {
    return s_forwarderAddress;
  }

  /// @notice Returns the expected workflow author address
  /// @return The expected author address (address(0) if not set)
  function getExpectedAuthor() external view returns (address) {
    return s_expectedAuthor;
  }

  /// @notice Returns the expected workflow name
  /// @return The expected workflow name (bytes10(0) if not set)
  function getExpectedWorkflowName() external view returns (bytes10) {
    return s_expectedWorkflowName;
  }

  /// @notice Returns the expected workflow ID
  /// @return The expected workflow ID (bytes32(0) if not set)
  function getExpectedWorkflowId() external view returns (bytes32) {
    return s_expectedWorkflowId;
  }

  /// @inheritdoc IReceiver
  /// @dev Performs optional validation checks based on which permission fields are set
  function onReport(
    bytes calldata metadata,
    bytes calldata report
  ) external override {
    // Security Check 1: Verify caller is the trusted Chainlink Forwarder (if configured)
    if (s_forwarderAddress != address(0) && msg.sender != s_forwarderAddress) {
      revert InvalidSender(msg.sender, s_forwarderAddress);
    }

    // Security Checks 2-4: Verify workflow identity - ID, owner, and/or name (if any are configured)
    if (s_expectedWorkflowId != bytes32(0) || s_expectedAuthor != address(0) || s_expectedWorkflowName != bytes10(0)) {
      (bytes32 workflowId, bytes10 workflowName, address workflowOwner) = _decodeMetadata(metadata);

      if (s_expectedWorkflowId != bytes32(0) && workflowId != s_expectedWorkflowId) {
        revert InvalidWorkflowId(workflowId, s_expectedWorkflowId);
      }
      if (s_expectedAuthor != address(0) && workflowOwner != s_expectedAuthor) {
        revert InvalidAuthor(workflowOwner, s_expectedAuthor);
      }

      // ================================================================
      // WORKFLOW NAME VALIDATION - REQUIRES AUTHOR VALIDATION
      // ================================================================
      // Do not rely on workflow name validation alone. Workflow names are unique
      // per owner, but not across owners.
      // Furthermore, workflow names use 40-bit truncation (bytes10), making collisions possible.
      // Therefore, workflow name validation REQUIRES author (workflow owner) validation.
      // The code enforces this dependency at runtime.
      // ================================================================
      if (s_expectedWorkflowName != bytes10(0)) {
        // Author must be configured if workflow name is used
        if (s_expectedAuthor == address(0)) {
          revert WorkflowNameRequiresAuthorValidation();
        }
        // Validate workflow name matches (author already validated above)
        if (workflowName != s_expectedWorkflowName) {
          revert InvalidWorkflowName(workflowName, s_expectedWorkflowName);
        }
      }
    }

    _processReport(report);
  }

  /// @notice Updates the forwarder address that is allowed to call onReport
  /// @param _forwarder The new forwarder address
  /// @dev WARNING: Setting to address(0) disables forwarder validation.
  ///      This makes your contract INSECURE - anyone can call onReport() with arbitrary data.
  ///      Only use address(0) if you fully understand the security implications.
  function setForwarderAddress(
    address _forwarder
  ) external onlyOwner {
    address previousForwarder = s_forwarderAddress;

    // Emit warning if disabling forwarder check
    if (_forwarder == address(0)) {
      emit SecurityWarning("Forwarder address set to zero - contract is now INSECURE");
    }

    s_forwarderAddress = _forwarder;
    emit ForwarderAddressUpdated(previousForwarder, _forwarder);
  }

  /// @notice Updates the expected workflow owner address
  /// @param _author The new expected author address (use address(0) to disable this check)
  function setExpectedAuthor(
    address _author
  ) external onlyOwner {
    address previousAuthor = s_expectedAuthor;
    s_expectedAuthor = _author;
    emit ExpectedAuthorUpdated(previousAuthor, _author);
  }

  /// @notice Updates the expected workflow name from a plaintext string
  /// @param _name The workflow name as a string (use empty string "" to disable this check)
  /// @dev IMPORTANT: Workflow name validation REQUIRES author validation to be enabled.
  ///      The workflow name uses only 40-bit truncation, making collision attacks feasible
  ///      when used alone. However, since workflow names are unique per owner, validating
  ///      both the name AND the author address provides adequate security.
  ///      You must call setExpectedAuthor() before or after calling this function.
  ///      The name is hashed using SHA256 and truncated to bytes10.
  function setExpectedWorkflowName(
    string calldata _name
  ) external onlyOwner {
    bytes10 previousName = s_expectedWorkflowName;

    if (bytes(_name).length == 0) {
      s_expectedWorkflowName = bytes10(0);
      emit ExpectedWorkflowNameUpdated(previousName, bytes10(0));
      return;
    }

    // Convert workflow name to bytes10:
    // SHA256 hash → hex encode → take first 10 chars → hex encode those chars
    bytes32 hash = sha256(bytes(_name));
    bytes memory hexString = _bytesToHexString(abi.encodePacked(hash));
    bytes memory first10 = new bytes(10);
    for (uint256 i = 0; i < 10; i++) {
      first10[i] = hexString[i];
    }
    s_expectedWorkflowName = bytes10(first10);
    emit ExpectedWorkflowNameUpdated(previousName, s_expectedWorkflowName);
  }

  /// @notice Updates the expected workflow ID
  /// @param _id The new expected workflow ID (use bytes32(0) to disable this check)
  function setExpectedWorkflowId(
    bytes32 _id
  ) external onlyOwner {
    bytes32 previousId = s_expectedWorkflowId;
    s_expectedWorkflowId = _id;
    emit ExpectedWorkflowIdUpdated(previousId, _id);
  }

  /// @notice Helper function to convert bytes to hex string
  /// @param data The bytes to convert
  /// @return The hex string representation
  function _bytesToHexString(
    bytes memory data
  ) private pure returns (bytes memory) {
    bytes memory hexString = new bytes(data.length * 2);

    for (uint256 i = 0; i < data.length; i++) {
      hexString[i * 2] = HEX_CHARS[uint8(data[i] >> 4)];
      hexString[i * 2 + 1] = HEX_CHARS[uint8(data[i] & 0x0f)];
    }

    return hexString;
  }

  /// @notice Extracts all metadata fields from the onReport metadata parameter
  /// @param metadata The metadata bytes encoded using abi.encodePacked(workflowId, workflowName, workflowOwner)
  /// @return workflowId The unique identifier of the workflow (bytes32)
  /// @return workflowName The name of the workflow (bytes10)
  /// @return workflowOwner The owner address of the workflow
  function _decodeMetadata(
    bytes memory metadata
  ) internal pure returns (bytes32 workflowId, bytes10 workflowName, address workflowOwner) {
    // Metadata structure (encoded using abi.encodePacked by the Forwarder):
    // - First 32 bytes: length of the byte array (standard for dynamic bytes)
    // - Offset 32, size 32: workflow_id (bytes32)
    // - Offset 64, size 10: workflow_name (bytes10)
    // - Offset 74, size 20: workflow_owner (address)
    assembly {
      workflowId := mload(add(metadata, 32))
      workflowName := mload(add(metadata, 64))
      workflowOwner := shr(mul(12, 8), mload(add(metadata, 74)))
    }
    return (workflowId, workflowName, workflowOwner);
  }

  /// @notice Abstract function to process the report data
  /// @param report The report calldata containing your workflow's encoded data
  /// @dev Implement this function with your contract's business logic
  function _processReport(
    bytes calldata report
  ) internal virtual;

  /// @inheritdoc IERC165
  function supportsInterface(
    bytes4 interfaceId
  ) public pure virtual override returns (bool) {
    return interfaceId == type(IReceiver).interfaceId || interfaceId == type(IERC165).interfaceId;
  }
}

contracts/RuleRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import { ReceiverTemplate } from "./interfaces/ReceiverTemplate.sol";
import { IERC20 } from "./interfaces/IERC20.sol";

/**
 * @title RuleRegistry
 * @author x402-cre-alerts
 * @notice On-chain registry for storing crypto price alert rules
 * 
 * @dev This contract serves as both:
 * 1. A Chainlink CRE (Chainlink Runtime Environment) receiver that accepts reports
 *    from CRE workflows containing price alert rules
 * 2. An x402 payment receiver that can accept STT payments and allow owner withdrawals
 * 
 * Architecture:
 * - Rules are written to the contract via CRE workflow reports
 * - Rules are stored in a mapping with incremental IDs for efficient iteration
 * - The contract can receive STT payments (from x402 protocol)
 * - Only the owner can withdraw accumulated STT
 * 
 * Flow:
 * 1. CRE workflow receives alert data from server
 * 2. CRE workflow encodes alert data and sends report to this contract
 * 3. Contract decodes report and stores rule in mapping
 * 4. CRE cron job monitors prices and checks rules against current prices
 * 5. When conditions are met, notifications are sent via Pushover API
 *
 * Somnia Reactivity (optional):
 * - Rules can also be written via on-chain reactivity: a trusted RuleRegistryReactivityHandler
 *   subscribes to events (e.g. RuleRequestEmitter.RuleRequested); when the chain invokes the
 *   handler, it calls writeRuleFromReactivity(data). Owner must set the handler via setReactivityHandler.
 */
contract RuleRegistry is ReceiverTemplate {
    // ============================================================================
    // Types & Data Structures
    // ============================================================================

    /**
     * @notice Price alert rule structure
     * @dev Rules are stored on-chain and can be queried by the CRE workflow
     * @param id Deterministic rule ID (SHA256 hash of alert data) - bytes32 for on-chain compatibility
     * @param asset Cryptocurrency asset symbol (e.g., "BTC", "ETH", "LINK")
     * @param condition Price condition: "gt", "lt", "gte", or "lte"
     * @param targetPriceUsd Target price in USD (stored as uint256, no decimals)
     * @param createdAt UNIX timestamp (seconds) when the rule was created
     */
    struct Rule {
        bytes32 id;
        string asset;
        string condition;
        uint256 targetPriceUsd;
        uint256 createdAt;
    }

    // ============================================================================
    // State Variables
    // ============================================================================

    /**
     * @notice STT token contract address
     * @dev Set in constructor, used for receiving x402 payments
     * @dev STT typically has 6 decimals
     */
    address public usdcToken;

    /**
     * @notice Trusted Somnia reactivity handler allowed to call writeRuleFromReactivity
     * @dev When set, only this address can submit rules via on-chain event reactivity
     */
    address public reactivityHandler;

    /**
     * @notice Next available rule ID
     * @dev Increments each time a new rule is written
     * @dev Used to iterate over all rules (0 to nextRuleId - 1)
     */
    uint256 public nextRuleId;

    /**
     * @notice Mapping from rule ID to Rule struct
     * @dev Rules are stored with incremental IDs starting from 0
     * @dev To get all rules, iterate from 0 to nextRuleId - 1
     */
    mapping(uint256 => Rule) public rules;

    // ============================================================================
    // Events
    // ============================================================================

    /**
     * @notice Emitted when a new rule is created
     * @param ruleId The incremental rule ID assigned to this rule
     * @param id The deterministic rule ID (bytes32 hash)
     * @param asset Cryptocurrency asset symbol
     * @param condition Price condition string
     * @param targetPriceUsd Target price in USD
     * @param createdAt UNIX timestamp when rule was created
     */
    event RuleCreated(
        uint256 indexed ruleId,
        bytes32 indexed id,
        string asset,
        string condition,
        uint256 targetPriceUsd,
        uint256 createdAt
    );

    /**
     * @notice Emitted when STT is withdrawn from the contract
     * @param token The token address (STT)
     * @param to The recipient address
     * @param amount The amount withdrawn (in STT's decimals, typically 6)
     */
    event Withdrawal(address indexed token, address indexed to, uint256 amount);

    /**
     * @notice Emitted when the Somnia reactivity handler is set or updated
     */
    event ReactivityHandlerUpdated(address indexed previousHandler, address indexed newHandler);

    // ============================================================================
    // Modifiers
    // ============================================================================

    modifier onlyReactivityHandler() {
        require(msg.sender == reactivityHandler, "RuleRegistry: caller is not the reactivity handler");
        _;
    }

    // ============================================================================
    // Constructor
    // ============================================================================

    /**
     * @notice Initializes the RuleRegistry contract
     * @dev Sets the owner to the deployer and configures STT token address and Chainlink Forwarder
     * @param _usdcToken Address of the STT token contract (for x402 payments)
     * @param _forwarderAddress Address of the Chainlink Forwarder contract (required for CRE report validation)
     * 
     * @custom:note The forwarder address is required for security - it ensures only verified CRE reports
     *             are processed. Find the correct forwarder address for your network in the CRE documentation.
     */
    constructor(address _usdcToken, address _forwarderAddress) ReceiverTemplate(_forwarderAddress) {
        require(_usdcToken != address(0), "RuleRegistry: STT token address cannot be zero");
        require(_forwarderAddress != address(0), "RuleRegistry: Forwarder address cannot be zero");
        usdcToken = _usdcToken;
    }

    // ============================================================================
    // Internal Functions
    // ============================================================================

    /**
     * @notice Writes a new rule to the registry
     * @dev Internal; called by _processReport (CRE) and writeRuleFromReactivity (Somnia reactivity)
     * @param _id Deterministic rule ID (bytes32 hash of alert data)
     * @param _asset Cryptocurrency asset symbol
     * @param _condition Price condition string ("gt", "lt", "gte", "lte")
     * @param _targetPriceUsd Target price in USD
     * @param _createdAt UNIX timestamp when rule was created
     * @return ruleId The incremental rule ID assigned to this rule
     */
    function _writeRule(
        bytes32 _id,
        string memory _asset,
        string memory _condition,
        uint256 _targetPriceUsd,
        uint256 _createdAt
    ) internal returns (uint256) {
        // Assign next available rule ID
        uint256 ruleId = nextRuleId;
        nextRuleId++;

        // Store rule in mapping
        rules[ruleId] = Rule({
            id: _id,
            asset: _asset,
            condition: _condition,
            targetPriceUsd: _targetPriceUsd,
            createdAt: _createdAt
        });

        // Emit event for off-chain indexing and monitoring
        emit RuleCreated(ruleId, _id, _asset, _condition, _targetPriceUsd, _createdAt);

        return ruleId;
    }

    // ============================================================================
    // CRE Workflow Integration (IReceiverTemplate Implementation)
    // ============================================================================

    /**
     * @notice Processes a report received from a Chainlink CRE workflow
     * @dev Internal function called by onReport after metadata validation
     * @dev Decodes the report bytes into rule parameters and writes to registry
     * @param report The encoded report data containing rule parameters
     * 
     * @custom:note Report format (ABI-encoded):
     *             - bytes32 id
     *             - string asset
     *             - string condition
     *             - uint256 targetPriceUsd
     *             - uint256 createdAt
     * 
     * @custom:note This function is called by the CRE workflow when it needs to
     *             write a new price alert rule on-chain. The CRE workflow receives
     *             alert data from the server and encodes it into this report format.
     */
    function _processReport(bytes calldata report) internal override {
        // Decode report data into rule parameters
        // The report is ABI-encoded with: (bytes32, string, string, uint256, uint256)
        (bytes32 id, string memory asset, string memory condition, uint256 targetPriceUsd, uint256 createdAt) =
            abi.decode(report, (bytes32, string, string, uint256, uint256));

        // Write rule to registry
        _writeRule(id, asset, condition, targetPriceUsd, createdAt);
    }

    // ============================================================================
    // Somnia Reactivity Integration
    // ============================================================================

    /**
     * @notice Set the trusted Somnia reactivity handler that can write rules via writeRuleFromReactivity
     * @dev Only callable by owner. Use address(0) to disable reactivity-based rule writes.
     * @param _handler Address of the deployed RuleRegistryReactivityHandler (or 0 to disable)
     */
    function setReactivityHandler(address _handler) external onlyOwner {
        address previous = reactivityHandler;
        reactivityHandler = _handler;
        emit ReactivityHandlerUpdated(previous, _handler);
    }

    /**
     * @notice Write a rule from Somnia on-chain reactivity (event-driven)
     * @dev Only the address set as reactivityHandler can call this. Decodes ABI-encoded
     *      (bytes32 id, string asset, string condition, uint256 targetPriceUsd, uint256 createdAt).
     * @param data ABI-encoded rule params; same format as CRE report payload
     */
    function writeRuleFromReactivity(bytes calldata data) external onlyReactivityHandler {
        (bytes32 id, string memory asset, string memory condition, uint256 targetPriceUsd, uint256 createdAt) =
            abi.decode(data, (bytes32, string, string, uint256, uint256));
        _writeRule(id, asset, condition, targetPriceUsd, createdAt);
    }

    // ============================================================================
    // Public View Functions
    // ============================================================================

    /**
     * @notice Retrieves a single rule by its rule ID
     * @dev Public view function for querying individual rules
     * @param _ruleId The incremental rule ID (0-indexed)
     * @return Rule struct containing all rule data
     * 
     * @custom:reverts If ruleId >= nextRuleId (rule doesn't exist)
     */
    function getRule(uint256 _ruleId) public view returns (Rule memory) {
        require(_ruleId < nextRuleId, "Rule does not exist");
        return rules[_ruleId];
    }

    /**
     * @notice Retrieves all rules stored in the registry
     * @dev Public view function that returns all rules as an array
     * @dev Iterates from rule ID 0 to nextRuleId - 1
     * @return Array of all Rule structs
     * 
     * @custom:gas This function can be gas-intensive for large numbers of rules.
     *             Consider using getRuleCount() and getRule() for pagination.
     */
    function getAllRules() public view returns (Rule[] memory) {
        // Allocate array with size equal to number of rules
        Rule[] memory allRules = new Rule[](nextRuleId);

        // Populate array by iterating over all rule IDs
        for (uint256 i = 0; i < nextRuleId; i++) {
            allRules[i] = rules[i];
        }

        return allRules;
    }

    /**
     * @notice Returns the total number of rules stored in the registry
     * @dev Useful for pagination and determining array sizes
     * @return The number of rules (equal to nextRuleId)
     */
    function getRuleCount() public view returns (uint256) {
        return nextRuleId;
    }

    // ============================================================================
    // x402 Payment Receiver Functions
    // ============================================================================

    /**
     * @notice Gets the STT balance of this contract
     * @dev This contract can receive STT payments via x402 protocol
     * @dev The balance accumulates as users pay for creating alerts
     * @return The STT balance of the contract (in STT's decimals, typically 6)
     * 
     * @custom:note STT has 6 decimals, so a return value of 1000000 represents 1 STT
     * 
     * @custom:reverts If usdcToken address is not set (should never happen after deployment)
     */
    function getUSDCBalance() external view returns (uint256) {
        require(usdcToken != address(0), "RuleRegistry: STT token address not set");
        IERC20 usdc = IERC20(usdcToken);
        return usdc.balanceOf(address(this));
    }

    /**
     * @notice Withdraws STT tokens from the contract
     * @dev Only the contract owner can withdraw accumulated STT payments
     * @dev This allows the owner to collect payments received via x402 protocol
     * @param to The address to send the STT to
     * @param amount The amount of STT to withdraw (in STT's decimals, typically 6)
     * 
     * @custom:note STT has 6 decimals, so to withdraw 1 STT, pass 1000000
     * 
     * @custom:reverts If:
     *             - Caller is not the owner
     *             - usdcToken address is not set
     *             - to address is zero
     *             - amount is zero
     *             - Contract balance is insufficient
     *             - STT transfer fails
     * 
     * @custom:emits Withdrawal event on successful withdrawal
     */
    function withdrawUSDC(address to, uint256 amount) external onlyOwner {
        require(usdcToken != address(0), "RuleRegistry: STT token address not set");
        require(to != address(0), "RuleRegistry: invalid recipient address");
        require(amount > 0, "RuleRegistry: amount must be greater than zero");

        IERC20 usdc = IERC20(usdcToken);
        uint256 balance = usdc.balanceOf(address(this));
        require(balance >= amount, "RuleRegistry: insufficient STT balance");

        // Transfer STT to recipient
        require(usdc.transfer(to, amount), "RuleRegistry: STT transfer failed");

        // Emit event for off-chain monitoring
        emit Withdrawal(usdcToken, to, amount);
    }
}

contracts/RuleRegistryReactivityHandler..content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import { SomniaEventHandler } from "@somnia-chain/reactivity-contracts/contracts/SomniaEventHandler.sol";
import { RuleRegistry } from "./RuleRegistry.sol";

/**
 * @title RuleRegistryReactivityHandler
 * @notice Somnia on-chain reactivity handler that forwards event data to RuleRegistry as new rules
 * @dev Subscribe this contract to events (e.g. RuleRequestEmitter.RuleRequested). When the chain
 *      invokes onEvent, this contract calls RuleRegistry.writeRuleFromReactivity(data). The registry
 *      must have this handler set via setReactivityHandler(address(this)).
 */
contract RuleRegistryReactivityHandler is SomniaEventHandler {

    RuleRegistry public immutable ruleRegistry;

    constructor(address _ruleRegistry) {
        require(_ruleRegistry != address(0), "RuleRegistryReactivityHandler: zero registry");
        ruleRegistry = RuleRegistry(_ruleRegistry);
    }

    /**
     * @notice Called by Somnia reactivity precompile when a subscribed event matches
     * @dev Forwards event data to RuleRegistry. Expects data to be ABI-encoded
     *      (bytes32 id, string asset, string condition, uint256 targetPriceUsd, uint256 createdAt)
     */
    function _onEvent(
        address /* emitter */,
        bytes32[] calldata /* eventTopics */,
        bytes calldata data
    ) internal override {
        ruleRegistry.writeRuleFromReactivity(data);
    }
}

contracts/RuleRequestEmitter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/**
 * @title RuleRequestEmitter
 * @notice Emits RuleRequested events for Somnia reactivity: subscribe RuleRegistryReactivityHandler
 *        to this contract's RuleRequested event so that rules are written to RuleRegistry on-chain
 * @dev No access control; anyone can emit. Filter by emitter in the reactivity subscription.
 *      Event data is ABI-encoded (bytes32, string, string, uint256, uint256) matching
 *      RuleRegistry.writeRuleFromReactivity / CRE report format.
 */
contract RuleRequestEmitter {

    event RuleRequested(
        bytes32 id,
        string asset,
        string condition,
        uint256 targetPriceUsd,
        uint256 createdAt
    );

    /**
     * @notice Request a rule to be written via reactivity (handler must be subscribed to this event)
     * @param id Deterministic rule ID (e.g. SHA256 hash of alert data)
     * @param asset Asset symbol (e.g. "BTC", "ETH", "LINK")
     * @param condition Condition ("gt", "lt", "gte", "lte")
     * @param targetPriceUsd Target price in USD
     * @param createdAt UNIX timestamp
     */
    function requestRule(
        bytes32 id,
        string calldata asset,
        string calldata condition,
        uint256 targetPriceUsd,
        uint256 createdAt
    ) external {
        emit RuleRequested(id, asset, condition, targetPriceUsd, createdAt);
    }
}

